import React, { useState, useEffect, useRef } from 'react';
import './ChatbotV2.css';
import './ResultsTable.css';
import './Timestamp.css';
import './DataTable.css';
import apiService from '../services/apiService';
import MarkdownRenderer from './MarkdownRenderer';
import DataInsightsPieChart from './DataInsightsPieChart';

/* -------------------- HELPER (OUTSIDE COMPONENT) -------------------- */
const shouldShowPieChart = (data) => {
  if (!Array.isArray(data) || data.length === 0) return false;

  const sample = data[0];
  const hasString = Object.values(sample).some(v => typeof v === 'string');
  const hasNumber = Object.values(sample).some(v => typeof v === 'number');

  return hasString && hasNumber;
};

const ChatbotV2 = () => {
  const [messages, setMessages] = useState([
    { text: "Hello! I'm your AI Data Assistant. I can help you analyze and retrieve insights from your data. Ask me anything!", sender: "bot", type: "text", timestamp: new Date() }
  ]);

  const [currentStep, setCurrentStep] = useState('queries');
  const [selectedDashboard, setSelectedDashboard] = useState('analytics');
  const [customQuery, setCustomQuery] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [expandedMessages, setExpandedMessages] = useState(new Set());
  const [showTechnicalInsights, setShowTechnicalInsights] = useState(false);
  const [latestTechnicalData, setLatestTechnicalData] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeTab, setActiveTab] = useState('sql');
  const [copySuccess, setCopySuccess] = useState(false);

  const messagesContainerRef = useRef(null);

  const scrollToBottom = (smooth = false) => {
    if (messagesContainerRef.current) {
      messagesContainerRef.current.scrollTo({
        top: messagesContainerRef.current.scrollHeight,
        behavior: smooth ? 'smooth' : 'auto'
      });
    }
  };

  useEffect(() => {
    if (messages.length <= 1) {
      scrollToBottom();
    }
  }, [messages]);

  /* -------------------- STREAMING (UNCHANGED) -------------------- */

  const handleStreamingResponse = async (query) => {
    try {
      setIsProcessing(true);
      const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3002/api/v1';

      const response = await fetch(`${API_BASE_URL}/chat/ask/stream`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: query })
      });

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let streamedContent = '';
      let buffer = '';
      let initialData = null;

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value);
        const lines = buffer.split('\n');
        buffer = lines.pop();

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;

          const dataStr = line.replace('data: ', '').trim();
          if (dataStr === '[DONE]') break;

          const data = JSON.parse(dataStr);

          if (data.type === 'start') {
            initialData = {
              sql: data.cortexData?.sql || null,
              results: data.cortexData?.results || data.cortexData?.rows || data.cortexData?.data || null
            };
          }

          if (data.type === 'chunk') {
            streamedContent += data.content || '';

            setMessages(prev => {
              const newMessages = [...prev];
              newMessages[newMessages.length - 1] = {
                text: streamedContent,
                sender: "bot",
                type: "markdown",
                timestamp: new Date()
              };
              return newMessages;
            });

            scrollToBottom(true);
          }

          if (data.type === 'complete') {
            setMessages(prev => {
              const newMessages = [...prev];
              const lastMessage = newMessages[newMessages.length - 1];

              lastMessage.technicalData = {
                sql: initialData?.sql || null,
                dataInsights: initialData?.results || null,
                rowCount: initialData?.results?.length || 0
              };

              console.log('📊 Data Insights:', lastMessage.technicalData.dataInsights);
              setLatestTechnicalData(lastMessage.technicalData);

              return newMessages;
            });

            setIsProcessing(false);
          }
        }
      }
    } catch (err) {
      console.error('Streaming error:', err);
      setIsProcessing(false);
    }
  };

  /* -------------------- UI SEND -------------------- */

  const handleCustomQuery = () => {
    if (!customQuery.trim() || isProcessing) return;

    const q = customQuery;
    setCustomQuery('');

    setMessages(prev => [
      ...prev,
      { text: q, sender: "user", type: "text", timestamp: new Date() },
      { text: "Thinking...", sender: "bot", type: "thinking", timestamp: new Date() }
    ]);

    handleStreamingResponse(q);
  };

  /* -------------------- RENDER -------------------- */

  return (
    <div className="chatbot-v2-container">

      <div className="chatbot-v2-header">
        <div className="header-info">
          <h2>Viola Communications</h2>
        </div>
      </div>

      <div className="chatbot-v2-content">
        <div className="messages-container" ref={messagesContainerRef}>
          {messages.map((message, index) => (
            <div key={index} className={`message-v2 ${message.sender}`}>
              <div className="message-content">
                <div className={`message-bubble ${message.type === 'thinking' ? 'thinking' : ''}`}>

                  {message.type === 'thinking' ? (
                    <>
                      {message.text}
                      <div className="thinking-dots"><span></span><span></span><span></span></div>
                    </>
                  ) : message.type === 'markdown' ? (
                    <>
                      <MarkdownRenderer content={message.text} />

                      {/* ✅ PIE CHART IN SAME BUBBLE */}
                      {message.sender === 'bot' &&
                        message.technicalData?.dataInsights &&
                        shouldShowPieChart(message.technicalData.dataInsights) && (
                          <div className="chat-chart-wrapper">
                            <DataInsightsPieChart data={message.technicalData.dataInsights} />
                          </div>
                        )}
                    </>
                  ) : (
                    <div style={{ whiteSpace: 'pre-line' }}>{message.text}</div>
                  )}

                  {message.technicalData && message.sender === 'bot' && (
                    <button
                      className="tech-insights-inline-btn"
                      onClick={() => {
                        setLatestTechnicalData(message.technicalData);
                        setActiveTab('sql');
                        setShowTechnicalInsights(true);
                      }}
                    >
                      Technical Insights
                    </button>
                  )}

                </div>

                <div className="message-timestamp">
                  {message.timestamp &&
                    new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="custom-input-section">
          <textarea
            value={customQuery}
            onChange={(e) => setCustomQuery(e.target.value)}
            placeholder="Type your question here..."
            disabled={isProcessing}
          />
          <button onClick={handleCustomQuery} disabled={isProcessing}>
            Ask Question
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatbotV2;
